import{_ as e,c as o,o as a,d as s}from"./app.426dd711.js";const h=JSON.parse('{"title":"Valores XP","description":"","frontmatter":{},"headers":[{"level":2,"title":"Los valores que impulsan XP","slug":"los-valores-que-impulsan-xp"}],"relativePath":"values/intro.md"}'),r={name:"values/intro.md"},l=s('<h1 id="valores-xp" tabindex="-1">Valores XP <a class="header-anchor" href="#valores-xp" aria-hidden="true">#</a></h1><blockquote><p>XP siendo como es, una metodolog\xEDa o disciplina de desarrollo tambi\xE9n proporciona una serie de valores para la creaci\xF3n de software. Estos valores no son fijos ni obligatorios y por esto pueden surgir discusiones sobre la necesidad de cumplirlos. Por esto cada equipo de creaci\xF3n de software que utilice XP posiblemente los vea de forma diferente o haya concebido alguno adicional que le dio buen resultado en otros proyectos.</p></blockquote><h2 id="los-valores-que-impulsan-xp" tabindex="-1">Los valores que impulsan XP <a class="header-anchor" href="#los-valores-que-impulsan-xp" aria-hidden="true">#</a></h2><p>El motor de XP se basa en cinco valores principales, los cuales aplicados de manera simult\xE1nea, impulsan la esencia colaborativa del equipo.</p><p>Estos valores son:</p><ol><li><strong>Comunicaci\xF3n</strong>: Todo se conversa cara a cara, procurando hallar soluciones en conjunto a los problemas que puedan surgir.</li><li><strong>Simplicidad</strong>: Lo m\xE1s simple es lo mejor, funciona mejor, m\xE1s r\xE1pido, es m\xE1s adaptable, m\xE1s barato y adem\xE1s es m\xE1s entendible.</li><li><strong>Retroalimentaci\xF3n</strong>: Hacer software implica entender qu\xE9 es lo que el Due\xF1o del Producto quiere y c\xF3mo entregar la mejor soluci\xF3n posible.</li><li><strong>Respeto</strong>: Se respeta la idoneidad del usuario respecto a las decisiones que aportan valor al negocio y la del equipo respecto al c\xF3mo esas decisiones deben ser desarrolladas.</li><li><strong>Coraje</strong>: Trabajar muy duro durante las horas dedicadas a ello y hablar con sinceridad sobre los avances y estimaciones del proyecto.</li></ol><p>Profundicemos dichos valores con m\xE1s precisi\xF3n.</p>',7),i=[l];function n(t,c,d,p,u,m){return a(),o("div",null,i)}const v=e(r,[["render",n]]);export{h as __pageData,v as default};
